mapper.select:
SELECT COUNT(*)
FROM COM_EML_SND
WHERE CO_ID = #{coId}
  AND EML_SND_STS_CD IN ('QUEUED', 'PROCESSING', 'PENDING', 'SUCCESS')

      AND EML_SUBJ_VAL = #{emlSubjVal}


      AND UPPER(EML_TO) = UPPER(#{emlTo})


      AND EML_SYS_MSG = #{emlSysMsg}

SELECT EML_ID, EML_TO, EML_CC, EML_BCC, EML_SUBJ_VAL, EML_SND_STS_CD, EML_SYS_MSG, EML_ATCH_ID, CRE_USR_ID, TO_CHAR(CRE_DT, 'YYYY-MM-DD HH24:MI:SS') AS CRE_DT FROM COM_EML_SND WHERE CO_ID = #{coId}
AND CRE_DT >= TO_TIMESTAMP(#{fromDate}, 'YYYY-MM-DD')
AND CRE_DT < TO_TIMESTAMP(#{toDate}, 'YYYY-MM-DD') + INTERVAL '1 day'
AND EML_SND_STS_CD = #{emlSndStsCd}
AND UPPER(EML_TO) LIKE '%' || UPPER(#{emlTo}) || '%'
AND UPPER(EML_SUBJ_VAL) LIKE '%' || UPPER(#{emlSubjVal}) || '%'
ORDER BY ${sort.sortField}
${sort.sortType}
ORDER BY CRE_DT DESC
LIMIT #{pagination.pageSize} OFFSET (#{pagination.current} - 1) * #{pagination.pageSize}

SELECT COUNT(*) FROM COM_EML_SND WHERE CO_ID = #{coId}
AND CRE_DT >= TO_TIMESTAMP(#{fromDate}, 'YYYY-MM-DD')
AND CRE_DT < TO_TIMESTAMP(#{toDate}, 'YYYY-MM-DD') + INTERVAL '1 day'
AND EML_SND_STS_CD = #{emlSndStsCd}
AND UPPER(EML_TO) LIKE '%' || UPPER(#{emlTo}) || '%'
AND UPPER(EML_SUBJ_VAL) LIKE '%' || UPPER(#{emlSubjVal}) || '%'

